var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":" 긴급지원요청이 들어왔습니다!","JPN":"緊急支援要請が入りました！","ENG":" We've got an urgent support request.","TWN":"緊急請求支援！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":" 방역임무를 맡고 있던 태스크포스 업체가 고위험 개체의 공격을 받아 도움이 필요하다고 합니다.","JPN":"防疫任務を担当していたタスクフォースカンパニーが、高レベルの危険個体による攻撃を受けたため、助けを求めているようです。","ENG":" A TASKFORCE company on a purge mission is under attack by some highly dangerous C.O.","TWN":"由於負責防疫任務的特遣势力公司受到高危險個體的攻擊，因此需要幫助。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":" 요즘 들어 지원요청이 엄청 많이 들어오는 거 같은데, 착각인가?","JPN":"最近支援要請がすごく多いみたいだけど、気のせい？","ENG":" Is it just me, or have there been a lot of requests like this as of late?","TWN":"最近好像有太多支援請求，是我想太多了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":" 착각이 아닐 겁니다, 미나 양. 지금은 범세계적으로 침식현상이 가장 왕성해지는 기간이에요.","JPN":"気のせいではありませんよ、ミナさん。今は全世界で、侵食現象が活発化する時期ですから。","ENG":" It isn't just you, Mina. The Counterside effect is at its most prolific around this time of the year.","TWN":"不是你想太多了，米娜小姐，因為現在是全世界侵蝕現象最旺盛的時期。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":" 공식 명칭은 아니지만, 태스크포스 업계에선 지금 같은 시기를 격전지원 시즌이라 부르고 있답니다.","JPN":"公式な名称ではありませんが、タスクフォースカンパニーでは今のような時期を激戦支援シーズンと呼んでいるんです。","ENG":" This isn't official yet, but the TASKFORCE industry has started calling it the Danger Close season.","TWN":"雖然非正式名稱，但在特遣勢力業界像現在這種時期稱為激戰支援賽季。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":" 시즌이라면...... 그럼 예전에도 이런 일이 꽤 자주 있었다는 거네?","JPN":"シーズンか……じゃあ、これまでも同じことがよくあったってこと？","ENG":" Season? Are you saying this isn't the first time it happened?","TWN":"賽季的話… 那麼以前也常發生類似的事情了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"예전엔 이 정도까진 아니었죠. 최근 들어서 그 주기가 많이 짧아지고 있습니다.","JPN":"以前はこれほどまでではありませんでした。最近、その周期がかなり短くなっていますね。","ENG":"No, but it was never this bad up until now. It's getting more frequent, too.","TWN":"以前可沒有像現在這樣，最近其週期變成更短。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 큰일인 거 아냐? .....부사장님은 웃고 있는 것 같은데?","JPN":"それって大変なことなんじゃないの？　……副社長は笑ってるみたいだけど？","ENG":"Then, it's serious... Why does the Vice President look like she's smiling?","TWN":"那不是大事嗎？… 副總好像在笑啊？"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마 그것도...... 착각은 아닐 겁니다.","JPN":"たぶんそれは……見間違いではないと思います。","ENG":"You're probably not wrong about that, either.","TWN":"也許那也...不會是錯覺吧。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"재난은 방치하면 비극이 되지만, 그건 막아내지 못했을 경우일 뿐입니다.","JPN":"災害は放置すれば悲劇になりますが、それは阻止できなかった場合のこと。","ENG":"Disaster leads to tragedy only if it's not contained beforehand.","TWN":"災難如果放置就會變成是悲劇，但那只是無法抵擋的情況而已。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리가 다른 곳에서 해내지 못한 문제를 처리하면 기업 이미지 향상에도 도움이 되고, 보수도 두둑하게 채울 수 있죠.","JPN":"私たちが他の会社では解決できなかった問題を処理すれば、企業のイメージアップにもなりますし、報酬もたっぷりいただけますから。","ENG":"By solving what others can't, we can improve our company's reputation and fatten our wallet at the same time.","TWN":"如果處理我們在其他地方沒能解決的問題，不僅有助於提高企業形象，而且還可以拿到豐厚的報酬。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래 봤자 지원 임무일 뿐인데, 보수라고 해봐야 얼마 못 받지 않아?","JPN":"それでも、たかが支援任務だし……報酬って言っても大したことないんじゃないの？","ENG":"How? I thought support missions like this didn't pay much.","TWN":"那還只不過是支援任務，即使是報酬也拿不到多少錢吧？"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"태스크포스가 맡은 임무를 해내지 못하면 당연히 관리지원금도 줄어들게 된다는 건 미나 양도 알고 있겠죠?","JPN":"タスクフォースカンパニーが受けた任務を完遂できなければ、当然管理局からの補助金も減るということは、ミナさんもご存知ですね？","ENG":"As you know, Mina, TASKFORCE companies that fail their missions have their support funds cut.","TWN":"如果特遣勢力無法完成負責的任務，管理支援金當然也會減少，米娜小姐應該也知道吧？"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 일이 되풀이되다 보면 관리국의 신용을 잃고 더 이상 지원도 받을 수 없게 됩니다.","JPN":"そんなことが繰り返されれば、管理局の信用を失って支援も受けられなくなるでしょう。","ENG":"And if it keeps happening, they will also lose the Administration's faith.","TWN":"如果反覆發生這樣的事情，就會失去管理局的信用，再也無法得到支援。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 불상사를 막으려면 어떻게든 실패를 막기 위해 다른 곳에서 힘을 빌려올 수 밖에 없을 테고요.","JPN":"そんな事態を防ぐには、どうにかして失敗を回避するために他から力を借りるしかないでしょう。","ENG":"To prevent that, they're desperate to do anything, even hiring other companies.","TWN":"要想阻止這種不祥之事，無論如何都要從別處借力，以免失敗。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 그에 대한 비용을 책정하는 건 순전히 힘을 빌려주는 쪽의 몫입니다.","JPN":"そして、その費用がいくらかを決めるのは、力を貸す側なんです。","ENG":"And it's up to the company that's being hired to set the price for its service.","TWN":"而且，決定相關費用純粹是借力的一方承擔。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이번 시즌에는 받아낼 수 있을 때 양껏 받아둬야죠.","JPN":"今回のシーズンでは搾り取れるだけ搾り取らないと。","ENG":"We'd better get as much as we can during this season.","TWN":"這個賽季能接受就要儘量接受才對。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그렇구나. 나중에 법적으로 덜미가 잡히고 그러진 않겠지?","JPN":"そ、そうなんだ……後で法的に問題になったりしないの？","ENG":"I-I see... Doing that isn't illegal or anything, is it?","TWN":"原、原來如此。 以後不會在法律上站不住腳吧？"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼요. 저희 현명하신 부사장님께선 다 계획이 있으시답니다.","JPN":"もちろんです。我らが賢明な副社長にはしっかりした計画があるので。","ENG":"Of course not. Our wise Vice President has plans for that, too.","TWN":"那當然，我們明智的副總會有計劃的。"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자, 그럼 사원 여러분? 우리 소중한 고객님들을 위해 지원을 나서보도록 할까요?","JPN":"さあ、社員の皆さん。大事なお客様のために、支援に乗り出すとしましょう。","ENG":"Now, everyone. Are you ready to go help our valued customers?","TWN":"那麼，各位員工們？ 為我們珍貴的顧客們提供支援吧？"},"stage":{"bg":"CORRIDOR","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};